<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Kanban Board</title>
    <!-- Tailwind CSS CDN -->
    <script src="https://cdn.tailwindcss.com"></script>
    <style>
        /* Custom styles for transitions and drag feedback */
        .kanban-column {
            min-height: 200px; /* Ensure columns are visible even when empty */
            transition: background-color 0.3s ease;
        }

        .card {
            cursor: grab;
            transition: transform 0.2s ease, box-shadow 0.2s ease;
        }

        .card:active {
            transform: scale(1.02);
            box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -2px rgba(0, 0, 0, 0.05);
        }

        /* Dragging styles */
        .dragging {
            opacity: 0.4;
            transform: scale(0.98);
        }

        /* Confetti animation setup */
        #confetti-container {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            pointer-events: none; /* Ensures clicks pass through */
            z-index: 50;
        }

        .confetti {
            position: absolute;
            width: 8px;
            height: 15px;
            opacity: 0;
            animation: fall linear infinite;
        }

        @keyframes fall {
            0% { transform: translateY(-10vh) rotate(0deg); opacity: 1; }
            100% { transform: translateY(100vh) rotate(720deg); opacity: 0.5; }
        }
    </style>
</head>
<body class="bg-gray-50 p-8 font-sans">

    <!-- Confetti Container -->
    <div id="confetti-container"></div>

    <!-- Main Kanban Board Structure -->
    <header class="text-center mb-10">
        <h1 class="text-4xl font-extrabold text-gray-900 tracking-tight">Project Flow Board</h1>
        <p class="text-gray-500 mt-2">Drag cards between stages to manage workflow.</p>
    </header>
